/**
 * Easing functions for voidmorphism transitions.
 * Includes standard eases plus custom ones tuned for morphing effects.
 */

export type EasingFunction = (t: number) => number;

export const linear: EasingFunction = (t) => t;

export const easeInOutCubic: EasingFunction = (t) =>
	t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;

export const easeOutExpo: EasingFunction = (t) =>
	t === 1 ? 1 : 1 - Math.pow(2, -10 * t);

export const easeInExpo: EasingFunction = (t) =>
	t === 0 ? 0 : Math.pow(2, 10 * t - 10);

export const easeInOutExpo: EasingFunction = (t) => {
	if (t === 0) return 0;
	if (t === 1) return 1;
	return t < 0.5
		? Math.pow(2, 20 * t - 10) / 2
		: (2 - Math.pow(2, -20 * t + 10)) / 2;
};

export const easeOutBack: EasingFunction = (t) => {
	const c1 = 1.70158;
	const c3 = c1 + 1;
	return 1 + c3 * Math.pow(t - 1, 3) + c1 * Math.pow(t - 1, 2);
};

export const easeInBack: EasingFunction = (t) => {
	const c1 = 1.70158;
	const c3 = c1 + 1;
	return c3 * t * t * t - c1 * t * t;
};

export const easeInOutBack: EasingFunction = (t) => {
	const c1 = 1.70158;
	const c2 = c1 * 1.525;
	return t < 0.5
		? (Math.pow(2 * t, 2) * ((c2 + 1) * 2 * t - c2)) / 2
		: (Math.pow(2 * t - 2, 2) * ((c2 + 1) * (t * 2 - 2) + c2) + 2) / 2;
};

export const easeOutElastic: EasingFunction = (t) => {
	const c4 = (2 * Math.PI) / 3;
	return t === 0
		? 0
		: t === 1
			? 1
			: Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * c4) + 1;
};

export const easeInElastic: EasingFunction = (t) => {
	const c4 = (2 * Math.PI) / 3;
	return t === 0
		? 0
		: t === 1
			? 1
			: -Math.pow(2, 10 * t - 10) * Math.sin((t * 10 - 10.75) * c4);
};

export const easeInOutElastic: EasingFunction = (t) => {
	const c5 = (2 * Math.PI) / 4.5;
	return t === 0
		? 0
		: t === 1
			? 1
			: t < 0.5
				? -(Math.pow(2, 20 * t - 10) * Math.sin((20 * t - 11.125) * c5)) / 2
				: (Math.pow(2, -20 * t + 10) * Math.sin((20 * t - 11.125) * c5)) / 2 + 1;
};

export const easeOutBounce: EasingFunction = (t) => {
	const n1 = 7.5625;
	const d1 = 2.75;
	if (t < 1 / d1) return n1 * t * t;
	if (t < 2 / d1) return n1 * (t -= 1.5 / d1) * t + 0.75;
	if (t < 2.5 / d1) return n1 * (t -= 2.25 / d1) * t + 0.9375;
	return n1 * (t -= 2.625 / d1) * t + 0.984375;
};

export const easeInBounce: EasingFunction = (t) =>
	1 - easeOutBounce(1 - t);

export const easeInOutBounce: EasingFunction = (t) =>
	t < 0.5
		? (1 - easeOutBounce(1 - 2 * t)) / 2
		: (1 + easeOutBounce(2 * t - 1)) / 2;

/* --- Cinematic eases (added for spacemorphism motion) -------------------- */

/** Gentle, symmetric sine ease — calm drifting feel. */
export const easeInOutSine: EasingFunction = (t) => -(Math.cos(Math.PI * t) - 1) / 2;

/** Sharp circular ease-out — fast launch, soft landing. */
export const easeOutCirc: EasingFunction = (t) => Math.sqrt(1 - Math.pow(t - 1, 2));

/** Anticipate — pulls back slightly before launching forward (overshoot at 0). */
export const anticipate: EasingFunction = (t) => {
	const s = 1.70158;
	return t * t * ((s + 1) * t - s);
};

/**
 * Glitch — digital glitch effect with RGB channel splitting and displacement.
 * Creates a "digital corruption" aesthetic perfect for tech/horror UIs.
 */

import type { TransitionConfig } from 'svelte/transition';
import { linear } from './easing.js';
import { random } from './utils.js';

export interface GlitchOptions {
	/** Duration in milliseconds. Default: 600 */
	duration?: number;
	/** Easing function. Default: linear */
	easing?: (t: number) => number;
	/** Maximum RGB channel split in pixels. Default: 8 */
	split?: number;
	/** Maximum horizontal displacement in pixels. Default: 20 */
	displacement?: number;
	/** Glitch intensity 0-1. Default: 1 */
	intensity?: number;
	/** Number of glitch steps/stutters. Default: 6 */
	steps?: number;
}

export function glitch(
	node: Element,
	options: GlitchOptions = {}
): TransitionConfig {
	const {
		duration = 600,
		easing = linear,
		split = 8,
		displacement = 20,
		intensity = 1,
		steps = 6
	} = options;

	return {
		duration,
		easing,
		css: (t: number) => {
			// Calculate which glitch step we're in
			const stepProgress = t * steps;
			const currentStep = Math.floor(stepProgress);
			const stepT = stepProgress - currentStep;

			// Random-ish displacement based on step (deterministic per render)
			const seed = currentStep * 0.73;
			const dx = Math.sin(seed * 99) * displacement * intensity * (1 - t);
			const dy = Math.cos(seed * 77) * displacement * 0.5 * intensity * (1 - t);
			const rShift = Math.sin(seed * 55) * split * intensity * (1 - t);
			const bShift = Math.cos(seed * 33) * split * intensity * (1 - t);

			// Flicker opacity
			const flicker = currentStep % 2 === 0 ? 1 : 0.7 + stepT * 0.3;
			const opacity = t * flicker;

			// Clip-path glitch slice
			const sliceTop = random(0, 80);
			const sliceHeight = random(5, 20);

			return `
				opacity: ${opacity};
				transform: translate(${dx}px, ${dy}px) scale(${1 + (1 - t) * 0.02});
				filter:
					drop-shadow(${rShift}px 0 0 rgba(255, 0, 0, ${intensity * (1 - t)}))
					drop-shadow(${bShift * -1}px 0 0 rgba(0, 100, 255, ${intensity * (1 - t)}));
				clip-path: polygon(
					0 0, 100% 0, 100% ${sliceTop}%, 0 ${sliceTop}%,
					0 ${sliceTop + sliceHeight}%, 100% ${sliceTop + sliceHeight}%,
					100% 100%, 0 100%
				);
			`;
		}
	};
}

/**
 * Utility functions for voidmorphism transitions.
 */

import type { EasingFunction } from './easing.js';

/**
 * Clamps a value between min and max.
 */
export function clamp(value: number, min: number, max: number): number {
	return Math.min(Math.max(value, min), max);
}

/**
 * Linear interpolation between two values.
 */
export function lerp(start: number, end: number, t: number): number {
	return start + (end - start) * t;
}

/**
 * Maps a value from one range to another.
 */
export function mapRange(
	value: number,
	inMin: number,
	inMax: number,
	outMin: number,
	outMax: number
): number {
	return ((value - inMin) * (outMax - outMin)) / (inMax - inMin) + outMin;
}

/**
 * Generates a random number between min and max.
 */
export function random(min: number, max: number): number {
	return Math.random() * (max - min) + min;
}

/**
 * Generates a random integer between min (inclusive) and max (inclusive).
 */
export function randomInt(min: number, max: number): number {
	return Math.floor(Math.random() * (max - min + 1)) + min;
}

/**
 * Creates a cubic-bezier easing function from control points.
 */
export function cubicBezier(
	x1: number,
	y1: number,
	x2: number,
	y2: number
): EasingFunction {
	return (t: number) => {
		// Use the control points to approximate the bezier curve
		const cx = 3 * x1;
		const bx = 3 * (x2 - x1) - cx;
		const ax = 1 - cx - bx;
		const cy = 3 * y1;
		const by = 3 * (y2 - y1) - cy;
		const ay = 1 - cy - by;

		// Solve for t given x (time), then return y (progress)
		let lo = 0;
		let hi = 1;
		let mid = t;

		for (let i = 0; i < 8; i++) {
			mid = (lo + hi) / 2;
			const x = ((ax * mid + bx) * mid + cx) * mid;
			if (x < t) lo = mid;
			else hi = mid;
		}

		return ((ay * mid + by) * mid + cy) * mid;
	};
}

/**
 * Creates a stepped easing function that jumps in discrete steps.
 */
export function steps(stepCount: number, start = false): EasingFunction {
	return (t: number) => {
		const step = 1 / stepCount;
		const result = Math.floor(t / step) * step;
		return start ? result + step : result;
	};
}

/**
 * Combines multiple easing functions sequentially.
 * Each easing applies to a segment of the total duration.
 */
export function sequenceEasing(
	...easings: Array<{ easing: EasingFunction; weight: number }>
): EasingFunction {
	const totalWeight = easings.reduce((sum, e) => sum + e.weight, 0);
	return (t: number) => {
		let accumulatedTime = 0;
		let accumulatedOutput = 0;
		for (const { easing, weight } of easings) {
			const segmentDuration = weight / totalWeight;
			if (t <= accumulatedTime + segmentDuration) {
				const localT = (t - accumulatedTime) / segmentDuration;
				return accumulatedOutput + easing(clamp(localT, 0, 1)) * segmentDuration;
			}
			accumulatedTime += segmentDuration;
			accumulatedOutput += segmentDuration;
		}
		return 1;
	};
}

