/**
 * dissolve — dissolves the element into space as it enters/exits, with blur,
 * a gentle swell, and a soft halo. The refined successor to the original
 * void-dissolve.
 */

import type { TransitionConfig } from 'svelte/transition';
import { linear } from './easing.js';

export interface DissolveOptions {
	/** Duration in milliseconds. Default: 800 */
	duration?: number;
	/** Easing function. Default: linear */
	easing?: (t: number) => number;
	/** Maximum blur in pixels. Default: 20 */
	blur?: number;
	/** Scale at peak dissolution. Default: 1.1 */
	scale?: number;
	/** Halo color (RGB components). Default: cold star-white '150, 195, 255' */
	color?: string;
}

export function dissolve(
	node: Element,
	options: DissolveOptions = {}
): TransitionConfig {
	const {
		duration = 800,
		easing = linear,
		blur = 20,
		scale = 1.1,
		color = '150, 195, 255'
	} = options;

	const originalFilter = (node as HTMLElement).style.filter || '';

	return {
		duration,
		easing,
		css: (t: number) => {
			const opacity = t;
			const currentBlur = (1 - t) * blur;
			const currentScale = lerpScale(scale, t);
			return `
				opacity: ${opacity};
				filter: ${originalFilter} blur(${currentBlur}px);
				transform: scale(${currentScale});
				box-shadow: 0 0 ${(1 - t) * 60}px rgba(${color}, ${(1 - t) * 0.8});
			`;
		}
	};
}

function lerpScale(target: number, t: number): number {
	// Peak at t=0.5, return to 1 at t=0 and t=1
	if (t < 0.5) {
		return 1 + (target - 1) * (t * 2);
	}
	return 1 + (target - 1) * ((1 - t) * 2);
}

/**
 * Easing functions for voidmorphism transitions.
 * Includes standard eases plus custom ones tuned for morphing effects.
 */

export type EasingFunction = (t: number) => number;

export const linear: EasingFunction = (t) => t;

export const easeInOutCubic: EasingFunction = (t) =>
	t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;

export const easeOutExpo: EasingFunction = (t) =>
	t === 1 ? 1 : 1 - Math.pow(2, -10 * t);

export const easeInExpo: EasingFunction = (t) =>
	t === 0 ? 0 : Math.pow(2, 10 * t - 10);

export const easeInOutExpo: EasingFunction = (t) => {
	if (t === 0) return 0;
	if (t === 1) return 1;
	return t < 0.5
		? Math.pow(2, 20 * t - 10) / 2
		: (2 - Math.pow(2, -20 * t + 10)) / 2;
};

export const easeOutBack: EasingFunction = (t) => {
	const c1 = 1.70158;
	const c3 = c1 + 1;
	return 1 + c3 * Math.pow(t - 1, 3) + c1 * Math.pow(t - 1, 2);
};

export const easeInBack: EasingFunction = (t) => {
	const c1 = 1.70158;
	const c3 = c1 + 1;
	return c3 * t * t * t - c1 * t * t;
};

export const easeInOutBack: EasingFunction = (t) => {
	const c1 = 1.70158;
	const c2 = c1 * 1.525;
	return t < 0.5
		? (Math.pow(2 * t, 2) * ((c2 + 1) * 2 * t - c2)) / 2
		: (Math.pow(2 * t - 2, 2) * ((c2 + 1) * (t * 2 - 2) + c2) + 2) / 2;
};

export const easeOutElastic: EasingFunction = (t) => {
	const c4 = (2 * Math.PI) / 3;
	return t === 0
		? 0
		: t === 1
			? 1
			: Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * c4) + 1;
};

export const easeInElastic: EasingFunction = (t) => {
	const c4 = (2 * Math.PI) / 3;
	return t === 0
		? 0
		: t === 1
			? 1
			: -Math.pow(2, 10 * t - 10) * Math.sin((t * 10 - 10.75) * c4);
};

export const easeInOutElastic: EasingFunction = (t) => {
	const c5 = (2 * Math.PI) / 4.5;
	return t === 0
		? 0
		: t === 1
			? 1
			: t < 0.5
				? -(Math.pow(2, 20 * t - 10) * Math.sin((20 * t - 11.125) * c5)) / 2
				: (Math.pow(2, -20 * t + 10) * Math.sin((20 * t - 11.125) * c5)) / 2 + 1;
};

export const easeOutBounce: EasingFunction = (t) => {
	const n1 = 7.5625;
	const d1 = 2.75;
	if (t < 1 / d1) return n1 * t * t;
	if (t < 2 / d1) return n1 * (t -= 1.5 / d1) * t + 0.75;
	if (t < 2.5 / d1) return n1 * (t -= 2.25 / d1) * t + 0.9375;
	return n1 * (t -= 2.625 / d1) * t + 0.984375;
};

export const easeInBounce: EasingFunction = (t) =>
	1 - easeOutBounce(1 - t);

export const easeInOutBounce: EasingFunction = (t) =>
	t < 0.5
		? (1 - easeOutBounce(1 - 2 * t)) / 2
		: (1 + easeOutBounce(2 * t - 1)) / 2;

/* --- Cinematic eases (added for spacemorphism motion) -------------------- */

/** Gentle, symmetric sine ease — calm drifting feel. */
export const easeInOutSine: EasingFunction = (t) => -(Math.cos(Math.PI * t) - 1) / 2;

/** Sharp circular ease-out — fast launch, soft landing. */
export const easeOutCirc: EasingFunction = (t) => Math.sqrt(1 - Math.pow(t - 1, 2));

/** Anticipate — pulls back slightly before launching forward (overshoot at 0). */
export const anticipate: EasingFunction = (t) => {
	const s = 1.70158;
	return t * t * ((s + 1) * t - s);
};

/**
 * resonance — a Svelte action that makes components react to nearby elements,
 * as if they share one continuous energy field. Surfaces near the pointer (and
 * therefore near each other) glow in unison, creating a living, unified material.
 *
 * It reads the pointer from the shared spacetime field and updates on the shared
 * rAF loop, so every resonant node pulses together rather than independently —
 * the "one substance" feel — with no per-node listeners.
 *
 * Usage:
 *   <div class="sm-surface" use:resonance>…</div>
 *   <div class="sm-surface" use:resonance={{ radius: 320, color: '212 90% 72%' }}>…</div>
 */

import { trackPointer, getPointer } from '../core/spacetime.js';
import { onFrame } from '../core/raf.js';
import { prefersReducedMotion } from '../core/env.js';

export interface ResonanceOptions {
	/** Radius (px) of the resonance field around the pointer. Default: 280. */
	radius?: number;
	/** Glow color as HSL components, e.g. '212 90% 72%'. Defaults to the cold accent. */
	color?: string;
	/** Peak glow intensity, 0–1. Default: 1. */
	intensity?: number;
	/** Disable the effect. Default: false. */
	disabled?: boolean;
}

export function resonance(node: HTMLElement, options: ResonanceOptions = {}) {
	let { radius = 280, color = '', intensity = 1, disabled = false } = options;
	const reduced = prefersReducedMotion();

	let current = 0;

	node.style.setProperty('--sm-resonance', '0 0 0 0 transparent');
	trackPointer();

	const stop = onFrame(() => {
		let target = 0;
		if (!disabled && !reduced) {
			const { x, y } = getPointer();
			const r = node.getBoundingClientRect();
			const cx = r.left + r.width / 2;
			const cy = r.top + r.height / 2;
			const dist = Math.hypot(x - cx, y - cy);
			target = Math.max(0, 1 - dist / radius);
		}
		current += (target - current) * 0.1;
		const g = current * intensity;
		const hsl = color || '212 90% 72%';
		node.style.setProperty(
			'--sm-resonance',
			`0 0 ${(20 + g * 60).toFixed(0)}px ${(-12 + g * 6).toFixed(0)}px hsla(${hsl}, ${(g * 0.55).toFixed(3)})`
		);
	});

	return {
		update(next: ResonanceOptions = {}) {
			({ radius = 280, color = '', intensity = 1, disabled = false } = next);
		},
		destroy() {
			stop();
		}
	};
}

/**
 * env — small, SSR-safe environment helpers shared across Spacemorphism.
 * Everything here is guarded so it can run during server rendering.
 */

export const isBrowser =
	typeof window !== 'undefined' && typeof document !== 'undefined';

/** Whether the user has asked for reduced motion. Safe on the server (→ false). */
export function prefersReducedMotion(): boolean {
	if (!isBrowser || typeof window.matchMedia !== 'function') return false;
	return window.matchMedia('(prefers-reduced-motion: reduce)').matches;
}

export type PerfTier = 'cinematic' | 'balanced' | 'eco';

export interface PerfSignals {
	/** navigator.hardwareConcurrency */
	cores?: number;
	/** navigator.deviceMemory (GB) */
	memory?: number;
	/** navigator.connection.saveData */
	saveData?: boolean;
	/** prefers-reduced-motion */
	reducedMotion?: boolean;
}

/**
 * Pure mapping from device signals → performance tier. Exported for testing.
 * - reduced-motion or save-data → eco
 * - plenty of cores + memory → cinematic
 * - constrained cores or memory → balanced
 */
export function perfTierFromSignals(s: PerfSignals): PerfTier {
	if (s.reducedMotion || s.saveData) return 'eco';
	const cores = s.cores ?? 4;
	const memory = s.memory ?? 4;
	if (cores >= 8 && memory >= 8) return 'cinematic';
	if (cores <= 4 || memory <= 4) return 'balanced';
	return 'balanced';
}

/** Detect the performance tier from the current device. SSR → 'balanced'. */
export function detectPerfTier(): PerfTier {
	if (!isBrowser) return 'balanced';
	const nav = navigator as Navigator & {
		deviceMemory?: number;
		connection?: { saveData?: boolean };
	};
	return perfTierFromSignals({
		cores: nav.hardwareConcurrency,
		memory: nav.deviceMemory,
		saveData: nav.connection?.saveData,
		reducedMotion: prefersReducedMotion()
	});
}

/**
 * raf — one shared requestAnimationFrame loop for the whole library, plus a
 * viewport-gating helper. Many animated components on a page should not each
 * spin their own rAF; they register here and are driven by a single loop.
 */

import { isBrowser } from './env.js';

type FrameCb = (time: number, dt: number) => void;

const callbacks = new Set<FrameCb>();
let running = false;
let last = 0;

function loop(time: number): void {
	const dt = last ? time - last : 16.7;
	last = time;
	for (const cb of callbacks) cb(time, dt);
	if (callbacks.size > 0) {
		requestAnimationFrame(loop);
	} else {
		running = false;
		last = 0;
	}
}

/**
 * Register a per-frame callback driven by the shared loop. Returns an
 * unsubscribe function. No-op driver on the server (callback never fires).
 */
export function onFrame(cb: FrameCb): () => void {
	callbacks.add(cb);
	if (isBrowser && !running && typeof requestAnimationFrame === 'function') {
		running = true;
		last = 0;
		requestAnimationFrame(loop);
	}
	return () => {
		callbacks.delete(cb);
	};
}

/** Number of active frame subscribers — exposed for testing. */
export function frameSubscriberCount(): number {
	return callbacks.size;
}

/**
 * Invoke `onChange(visible)` as `node` enters/leaves the viewport so heavy
 * loops can pause off-screen. Falls back to always-visible without IO/SSR.
 * Returns a cleanup function.
 */
export function whenVisible(
	node: Element,
	onChange: (visible: boolean) => void
): () => void {
	if (!isBrowser || typeof IntersectionObserver === 'undefined') {
		onChange(true);
		return () => {};
	}
	const io = new IntersectionObserver(
		(entries) => {
			for (const entry of entries) onChange(entry.isIntersecting);
		},
		{ rootMargin: '160px' }
	);
	io.observe(node);
	return () => io.disconnect();
}

/**
 * spacetime — the shared, page-wide gravitational field.
 *
 * The conceptual signature of Spacemorphism: the whole page is one region of
 * spacetime. The pointer is a moving mass; every registered surface lenses and
 * tilts toward it, and star-dust accelerates toward it. Rather than each
 * component running its own pointer listener and rAF, they all register here so
 * there is exactly ONE listener and ONE loop driving the entire field.
 *
 *   import { registerBody, getPointer } from 'svelte-spacemorphism';
 */

import { isBrowser, prefersReducedMotion } from './env.js';
import { onFrame } from './raf.js';

/* ----------------------------- pure helpers ----------------------------- */

/** Normalized 0→1 attraction given distance from an edge and a field radius. */
export function proximity(dist: number, field: number): number {
	if (field <= 0) return 0;
	return Math.max(0, 1 - dist / field);
}

/** One step of critically-damped easing toward a target. */
export function damp(cur: number, target: number, k = 0.12): number {
	return cur + (target - cur) * k;
}

/** Tilt (deg) toward the pointer; surface leans INTO the cursor. */
export function tiltFor(
	dx: number,
	dy: number,
	halfW: number,
	halfH: number,
	field: number,
	max: number
): { tx: number; ty: number } {
	const nx = clamp(dx / (halfW + field), -1, 1);
	const ny = clamp(dy / (halfH + field), -1, 1);
	return { tx: -ny * max, ty: nx * max };
}

function clamp(v: number, min: number, max: number): number {
	return Math.min(Math.max(v, min), max);
}

/* ----------------------------- the field -------------------------------- */

export interface BodyOptions {
	/** Max tilt in degrees toward the cursor. Default: 6. */
	tilt?: number;
	/** Px beyond the element bounds where attraction begins. Default: 120. */
	field?: number;
	/** Strength of the response, 0–1. Default: 1. */
	pull?: number;
	/** Disable this body's response. Default: false. */
	disabled?: boolean;
}

export interface BodyHandle {
	update(options: BodyOptions): void;
	destroy(): void;
}

interface Body {
	node: HTMLElement;
	tilt: number;
	field: number;
	pull: number;
	disabled: boolean;
	curPull: number;
	curTiltX: number;
	curTiltY: number;
}

const bodies = new Set<Body>();

let pointerX = -99999;
let pointerY = -99999;
let velX = 0;
let velY = 0;
let lastMoveT = 0;
let mass = 1;

let pointerTracking = false;
let looping = false;
let reduced = false;
let stopFrame: (() => void) | null = null;

function onMove(e: PointerEvent): void {
	const now = performance.now();
	const dt = lastMoveT ? Math.max(now - lastMoveT, 1) : 16;
	velX = (e.clientX - pointerX) / dt;
	velY = (e.clientY - pointerY) / dt;
	lastMoveT = now;
	pointerX = e.clientX;
	pointerY = e.clientY;
	if (isBrowser) {
		const root = document.documentElement;
		root.style.setProperty('--sm-px', `${pointerX}px`);
		root.style.setProperty('--sm-py', `${pointerY}px`);
	}
}

function updateBody(b: Body): void {
	const r = b.node.getBoundingClientRect();
	const cx = r.left + r.width / 2;
	const cy = r.top + r.height / 2;

	let targetPull = 0;
	let targetTiltX = 0;
	let targetTiltY = 0;

	if (!b.disabled && !reduced) {
		const localX = ((pointerX - r.left) / r.width) * 100;
		const localY = ((pointerY - r.top) / r.height) * 100;
		b.node.style.setProperty('--sm-mx', `${localX.toFixed(1)}%`);
		b.node.style.setProperty('--sm-my', `${localY.toFixed(1)}%`);

		const dx = Math.max(Math.abs(pointerX - cx) - r.width / 2, 0);
		const dy = Math.max(Math.abs(pointerY - cy) - r.height / 2, 0);
		const dist = Math.hypot(dx, dy);
		targetPull = proximity(dist, b.field) * b.pull;

		const tilt = tiltFor(pointerX - cx, pointerY - cy, r.width / 2, r.height / 2, b.field, b.tilt);
		targetTiltX = tilt.tx;
		targetTiltY = tilt.ty;
	}

	b.curPull = damp(b.curPull, targetPull);
	b.curTiltX = damp(b.curTiltX, targetTiltX);
	b.curTiltY = damp(b.curTiltY, targetTiltY);

	b.node.style.setProperty('--sm-pull', b.curPull.toFixed(3));
	b.node.style.setProperty('--sm-tilt-x', `${b.curTiltX.toFixed(2)}deg`);
	b.node.style.setProperty('--sm-tilt-y', `${b.curTiltY.toFixed(2)}deg`);
}

function tick(): void {
	for (const b of bodies) updateBody(b);
}

/**
 * Start the single page-wide pointer listener (idempotent). Star-dust and the
 * comet cursor call this so the field's pointer is live even with no bodies.
 */
export function trackPointer(): void {
	if (pointerTracking || !isBrowser) return;
	pointerTracking = true;
	reduced = prefersReducedMotion();
	window.addEventListener('pointermove', onMove, { passive: true });
}

function startLoop(): void {
	if (looping || !isBrowser) return;
	looping = true;
	stopFrame = onFrame(tick);
}

function maybeStopLoop(): void {
	if (bodies.size === 0 && stopFrame) {
		stopFrame();
		stopFrame = null;
		looping = false;
	}
}

/** Register a DOM node as a gravitational body. Returns update/destroy. */
export function registerBody(node: HTMLElement, options: BodyOptions = {}): BodyHandle {
	const body: Body = {
		node,
		tilt: options.tilt ?? 6,
		field: options.field ?? 120,
		pull: options.pull ?? 1,
		disabled: options.disabled ?? false,
		curPull: 0,
		curTiltX: 0,
		curTiltY: 0
	};
	bodies.add(body);
	trackPointer();
	startLoop();
	return {
		update(next: BodyOptions) {
			if (next.tilt !== undefined) body.tilt = next.tilt;
			if (next.field !== undefined) body.field = next.field;
			if (next.pull !== undefined) body.pull = next.pull;
			if (next.disabled !== undefined) body.disabled = next.disabled;
		},
		destroy() {
			bodies.delete(body);
			// Reset the node so it doesn't freeze mid-pull.
			body.node.style.setProperty('--sm-pull', '0');
			body.node.style.setProperty('--sm-tilt-x', '0deg');
			body.node.style.setProperty('--sm-tilt-y', '0deg');
			maybeStopLoop();
		}
	};
}

/** Current pointer position + velocity (px, px/ms). For star-dust / cursor. */
export function getPointer(): { x: number; y: number; vx: number; vy: number } {
	return { x: pointerX, y: pointerY, vx: velX, vy: velY };
}

/** The mass of the field's moving body (the cursor). Scales gravity strength. */
export function getMass(): number {
	return mass;
}
export function setMass(m: number): void {
	mass = Math.max(0, m);
}

/** Number of registered bodies — exposed for testing. */
export function bodyCount(): number {
	return bodies.size;
}

/**
 * gravityWell — a Svelte action that makes a surface feel massive.
 *
 * As the pointer approaches, the element:
 *   - attracts starlight toward the cursor (writes --sm-mx / --sm-my)
 *   - registers a gravitational "pull" (--sm-pull, 0 → 1)
 *   - tilts gently toward the cursor (--sm-tilt-x / --sm-tilt-y)
 *
 * These CSS variables are consumed by `.sm-surface` in spacemorphism.css.
 * The actual physics run in the shared spacetime field (one listener + one
 * rAF for the whole page) — this action just registers the node as a body.
 *
 * Usage:
 *   <div class="sm-surface" use:gravityWell={{ tilt: 6, pull: 1 }}>…</div>
 */

import { registerBody } from '../core/spacetime.js';

export interface GravityWellOptions {
	/** Max tilt in degrees toward the cursor. Default: 6. Set 0 to disable tilt. */
	tilt?: number;
	/** Strength of the light/pull response, 0–1. Default: 1. */
	pull?: number;
	/** Radius (px) beyond the element bounds where attraction begins. Default: 120. */
	field?: number;
	/** Disable the whole effect (e.g. for reduced motion). Default: false. */
	disabled?: boolean;
}

export function gravityWell(node: HTMLElement, options: GravityWellOptions = {}) {
	const handle = registerBody(node, options);
	return {
		update(next: GravityWellOptions = {}) {
			handle.update(next);
		},
		destroy() {
			handle.destroy();
		}
	};
}

/**
 * resonance — a Svelte action that makes components react to nearby elements,
 * as if they share one continuous energy field. Surfaces near the pointer (and
 * therefore near each other) glow in unison, creating a living, unified material.
 *
 * It reads the pointer from the shared spacetime field and updates on the shared
 * rAF loop, so every resonant node pulses together rather than independently —
 * the "one substance" feel — with no per-node listeners.
 *
 * Usage:
 *   <div class="sm-surface" use:resonance>…</div>
 *   <div class="sm-surface" use:resonance={{ radius: 320, color: '212 90% 72%' }}>…</div>
 */

import { trackPointer, getPointer } from '../core/spacetime.js';
import { onFrame } from '../core/raf.js';
import { prefersReducedMotion } from '../core/env.js';

export interface ResonanceOptions {
	/** Radius (px) of the resonance field around the pointer. Default: 280. */
	radius?: number;
	/** Glow color as HSL components, e.g. '212 90% 72%'. Defaults to the cold accent. */
	color?: string;
	/** Peak glow intensity, 0–1. Default: 1. */
	intensity?: number;
	/** Disable the effect. Default: false. */
	disabled?: boolean;
}

export function resonance(node: HTMLElement, options: ResonanceOptions = {}) {
	let { radius = 280, color = '', intensity = 1, disabled = false } = options;
	const reduced = prefersReducedMotion();

	let current = 0;

	node.style.setProperty('--sm-resonance', '0 0 0 0 transparent');
	trackPointer();

	const stop = onFrame(() => {
		let target = 0;
		if (!disabled && !reduced) {
			const { x, y } = getPointer();
			const r = node.getBoundingClientRect();
			const cx = r.left + r.width / 2;
			const cy = r.top + r.height / 2;
			const dist = Math.hypot(x - cx, y - cy);
			target = Math.max(0, 1 - dist / radius);
		}
		current += (target - current) * 0.1;
		const g = current * intensity;
		const hsl = color || '212 90% 72%';
		node.style.setProperty(
			'--sm-resonance',
			`0 0 ${(20 + g * 60).toFixed(0)}px ${(-12 + g * 6).toFixed(0)}px hsla(${hsl}, ${(g * 0.55).toFixed(3)})`
		);
	});

	return {
		update(next: ResonanceOptions = {}) {
			({ radius = 280, color = '', intensity = 1, disabled = false } = next);
		},
		destroy() {
			stop();
		}
	};
}

